implementation_steps.step:
修改 src/mapek/execute.py 中的 _call_coach_agent() 等方法，
从占位返回改为真实调用：

```python
def _call_coach_agent(self, plan: dict, context: dict) -> dict:
    """委托 CoachAgent 生成 DSL 动作包（当前已在 act() 中完成，此处记录）。"""
    return {
        "target": "CoachAgent",
        "success": True,
        "action": plan.get("target_action_type", "suggest"),
        "note": "CoachAgent.act() handles DSL generation — Execute records outcome",
    }

def _write_ledger(self, plan: dict) -> dict:
    """真实写入 ledger（通过 EventStore.append_event）。"""
    try:
        from src.inner.ledger.event_store import EventStore
        store = EventStore()
        # 写入 MAPE-K Plan 事件
        store.append_event(
            event_type="mapek_plan",
            payload={
                "target_action_type": plan.get("target_action_type"),
                "intensity": plan.get("intensity"),
                "horizon": plan.get("horizon_steps"),
                "confidence": plan.get("confidence"),
            },
        )
        return {"target": "Ledger", "success": True}
    except Exception as e:
        return {"target": "Ledger", "success": False, "error": str(e)}
```

注意：如果 EventStore.append_event() 的签名与实际不符，适配为实际签名。
参考 src/inner/ledger/event_store.py。
